/* BASE DE DATOS COMPLETA: 80 PREGUNTAS (4 OPCIONES CADA UNA) - ADIPLE (TEMA 4) */
const EXAM_DATA = [
    // --- PREGUNTAS DE LA PLATAFORMA (REFORMULADAS) ---
    { u: "ADIPLE T4", q: "Desde la óptica de la ventaja competitiva propuesta por Porter, ¿cuál de las siguientes opciones NO encaja como estrategia genérica?", opts: ["Liderazgo general en costes.", "Estrategia basada en la diferenciación.", "Estrategia de concentración o enfoque.", "Estrategia de diversificación corporativa."], ans: 3, exp: "La diversificación es una vía de expansión reflejada en la Matriz de Ansoff, pero las estrategias base de Porter son solo tres: costes, diferenciación y nicho/enfoque." },
    { u: "ADIPLE T4", q: "Al clasificar la información obtenida para una investigación de mercados, ¿cuál de los siguientes NO representa un criterio metodológico formal?", opts: ["Por su naturaleza (cuantitativa/cualitativa).", "Por su ubicación de procedencia (internos/externos).", "Por la temporalidad de la fuente (primarios/secundarios).", "Por su costo de adquisición."], ans: 3, exp: "El coste económico influye en la viabilidad del estudio, pero académicamente la información no se clasifica por su precio." },
    { u: "ADIPLE T4", q: "Todo estudio de mercado riguroso debe iniciarse obligatoriamente con la siguiente etapa:", opts: ["Procesamiento analítico de la información.", "Recopilación de los datos de campo.", "Definición del problema y planteamiento de los objetivos de investigación.", "Redacción y exposición de las conclusiones."], ans: 2, exp: "Si no existe un problema claramente definido ni unos objetivos concretos, cualquier esfuerzo de recolección de datos carecerá de sentido." },
    { u: "ADIPLE T4", q: "Para diagnosticar la posición de una compañía y cimentar su estrategia de marketing, la herramienta analítica por excelencia es:", opts: ["La inversión en pautas publicitarias.", "La matriz de diagnóstico DAFO (FODA).", "La política agresiva de precios.", "La red de transporte y logística."], ans: 1, exp: "El DAFO proporciona la fotografía exacta del entorno interno y externo que la empresa necesita para tomar decisiones a largo plazo." },
    { u: "ADIPLE T4", q: "Si nuestro objetivo es obtener datos estadísticos robustos (cuantitativos), ¿qué técnica deberíamos implementar?", opts: ["Focus group o dinámicas grupales.", "Entrevistas individuales abiertas.", "Lanzamiento de encuestas cerradas a una muestra representativa.", "Métodos de observación etnográfica."], ans: 2, exp: "La encuesta permite estandarizar respuestas y procesar estadísticamente los resultados para inferir tendencias." },
    { u: "ADIPLE T4", q: "El subconjunto de consumidores que comparten características comunes y hacia el cual la empresa orienta su esfuerzo comercial recibe el nombre de:", opts: ["Porción de demanda.", "Público objetivo, Target o mercado meta.", "Nicho hiperspecializado.", "Volumen de mercado potencial."], ans: 1, exp: "Identificar correctamente al target permite rentabilizar las campañas publicitarias y diseñar productos a medida." },
    { u: "ADIPLE T4", q: "¿Qué método de investigación implica modificar intencionadamente una o más variables para observar su efecto sobre el comportamiento del consumidor?", opts: ["Técnica de entrevista.", "Lanzamiento de un panel.", "Diseño experimental o experimentación.", "Mistery shopping."], ans: 2, exp: "La experimentación es la única forma empírica de determinar, por ejemplo, si bajar el precio 1 euro aumentará realmente las ventas." },
    { u: "ADIPLE T4", q: "Según el modelo de expansión de Ansoff, si decidimos comercializar artículos completamente nuevos en mercados donde no operábamos, aplicamos una estrategia de:", opts: ["Ampliación de la cuota actual.", "Renovación del catálogo (Desarrollo de producto).", "Apertura de nuevos territorios geográficos.", "Diversificación pura."], ans: 3, exp: "Es el cuadrante más arriesgado al implicar el lanzamiento de algo desconocido hacia un cliente también desconocido." },
    { u: "ADIPLE T4", q: "El propósito central de la herramienta PESTEL es escrutar:", opts: ["Las vulnerabilidades estructurales del negocio.", "Las fuerzas competitivas directas (microentorno).", "Las fuerzas globales o macroentorno que impactan a todas las organizaciones.", "El índice de retención de la cartera de clientes."], ans: 2, exp: "Contempla variables políticas, económicas, socioculturales, tecnológicas, medioambientales y legales." },
    { u: "ADIPLE T4", q: "Dentro de la segmentación de mercados, usar como filtro el nivel de renta, el género o la edad del consumidor se clasifica como segmentación:", opts: ["De corte psicográfico o actitudinal.", "De localización geográfica.", "De tipo sociodemográfico.", "Por beneficio esperado."], ans: 2, exp: "Son métricas cuantificables y universales que permiten acotar rápidamente la base poblacional." },

    // --- BLOQUE CUESTIONARIO AUTOEVALUACIÓN (REFORMULADO) ---
    { u: "ADIPLE T4", q: "¿En qué consiste la vertiente del 'Marketing Estratégico'?", opts: ["En la gestión diaria de las redes sociales.", "En la labor de prospección, análisis del entorno competitivo y definición del rumbo a medio-largo plazo.", "En la atención personalizada al comprador final.", "En el aprovisionamiento de materias primas."], ans: 1, exp: "Es la fase analítica y de planificación; debe preceder siempre a la acción comercial." },
    { u: "ADIPLE T4", q: "El 'Marketing Operativo', por su parte, se responsabiliza de:", opts: ["Trazar la misión corporativa.", "Articular las 4P (producto, precio, distribución y promoción) para ejecutar la estrategia a corto plazo.", "Elaborar balances de situación financiera.", "Inscribir la empresa en el registro mercantil."], ans: 1, exp: "Convierte las grandes directrices en acciones tangibles y medibles que el mercado puede percibir." },
    { u: "ADIPLE T4", q: "En el contexto de la investigación comercial, ¿a qué llamamos 'Datos Secundarios'?", opts: ["A aquellos datos recabados en tiempo real mediante encuestas propias.", "A la información preexistente, compilada con anterioridad por terceros o por la propia firma para otros fines.", "A la información que carece de relevancia estadística.", "A métricas temporales de muy corta duración."], ans: 1, exp: "Son el primer recurso a consultar por ser más económicos y rápidos de obtener (ej. estudios sectoriales o el INE)." },
    { u: "ADIPLE T4", q: "La metodología conocida como 'Cliente Misterioso' (Mystery Shopping) tiene el propósito de:", opts: ["Adquirir saldos en liquidación.", "Auditar de incógnito el cumplimiento de protocolos de venta y la calidad del trato dispensado al cliente.", "Realizar arqueos de caja sorpresivos.", "Idear nuevas marcas gráficas."], ans: 1, exp: "Permite a la dirección comprobar si la experiencia real de compra se ajusta al estándar deseado." },
    { u: "ADIPLE T4", q: "¿Qué utilidad proporciona un 'Panel de Consumo' continuo?", opts: ["Organizar asambleas extraordinarias de accionistas.", "Registrar y monitorizar las variaciones en los patrones de compra de un mismo grupo representativo de hogares a lo largo del tiempo.", "Instalar dispositivos de medición eléctrica.", "Realizar barridos telefónicos aleatorios."], ans: 1, exp: "Es clave para detectar tendencias, fidelidad a la marca o el impacto real de las promociones continuadas." },
    { u: "ADIPLE T4", q: "Al aplicar una estrategia de 'Penetración de Mercado' (Ansoff), la compañía persigue:", opts: ["Introducir innovaciones tecnológicas disruptivas.", "Maximar la cuota de ventas de sus artículos actuales entre su base de consumidores existente o robando clientes directos.", "Exportar su catálogo al continente asiático.", "Liquidar sus activos y disolver la entidad."], ans: 1, exp: "Suele implicar fuertes campañas de rebajas, bonos de fidelización o aumento del presupuesto en publicidad masiva." },
    { u: "ADIPLE T4", q: "La directriz estratégica de 'Desarrollo de Mercados' requiere que la empresa:", opts: ["Rediseñe por completo la fisonomía de su producto estrella.", "Incursione con su catálogo actual en nuevas plazas geográficas o se dirija a perfiles demográficos inéditos.", "Aplique una drástica reducción de precios de venta.", "Patrocine eventos deportivos masivos."], ans: 1, exp: "Aprovechamos nuestro conocimiento productivo pero buscamos caladeros de clientes diferentes (ej. exportación)." },
    { u: "ADIPLE T4", q: "¿Cómo podemos definir conceptualmente la 'Ventaja Competitiva'?", opts: ["La mera contratación masiva de fuerza laboral.", "Cualquier atributo sostenible en el tiempo que sitúe a la marca en una posición de clara superioridad frente a sus rivales.", "La tenencia de un almacén de grandes dimensiones.", "La obtención de subvenciones o exenciones fiscales ocasionales."], ans: 1, exp: "Es el escudo protector del negocio. Puede estar basada en tecnología puntera, monopolio logístico o marca irremplazable." },
    { u: "ADIPLE T4", q: "Apostar por una estrategia de 'Diferenciación' persigue como fin último que el mercado perciba nuestra oferta como:", opts: ["La opción económicamente más accesible.", "Un producto excepcional, singular y provisto de un valor añadido por el que vale la pena pagar más.", "Un bien de consumo estandarizado y genérico.", "Una marca invisible en el lineal."], ans: 1, exp: "La diferenciación reduce la sensibilidad al precio, generando márgenes de beneficio muy atractivos (ej. Apple)." },
    { u: "ADIPLE T4", q: "Implementar un enfoque estratégico de 'Nicho' o Alta Especialización implica:", opts: ["Diluir el esfuerzo abarcando la totalidad del mercado poblacional.", "Concentrar todos los recursos en satisfacer las exigencias de un segmento reducido y muy concreto de la demanda.", "Centrar la estrategia en la fotografía comercial.", "Engrosar desmesuradamente la pirámide directiva."], ans: 1, exp: "Las pymes suelen usar esta vía para evitar enfrentarse frontalmente a los gigantes corporativos." },
    { u: "ADIPLE T4", q: "Al estructurar una matriz DAFO, catalogamos como 'Oportunidad' a:", opts: ["Una eficiencia operativa de nuestro departamento de producción.", "Una coyuntura externa favorable (ej. cambios normativos o caída de rivales) que nuestro modelo de negocio puede capitalizar.", "Un tropiezo atribuible a la gerencia.", "Una inyección de capital por parte de inversores existentes."], ans: 1, exp: "Las oportunidades no dependen de nosotros, pero podemos posicionarnos para aprovecharlas." },
    { u: "ADIPLE T4", q: "Dentro del esquema analítico DAFO, el concepto de 'Debilidad' se asocia a:", opts: ["Un riesgo inminente proveniente de la competencia extranjera.", "Una tara o insuficiencia endógena que merma la competitividad o la operativa de la propia empresa.", "Un cuadro clínico que afecta a la fuerza productiva.", "Condiciones meteorológicas desfavorables prolongadas."], ans: 1, exp: "Por ejemplo: una maquinaria obsoleta, falta de digitalización o bajo nivel de liquidez." },
    { u: "ADIPLE T4", q: "Al desglosar el macroentorno mediante PESTEL, la letra 'S' hace referencia a factores:", opts: ["Socioculturales (pirámide poblacional, tendencias éticas, niveles formativos...).", "Seguridad integral de los sistemas cibernéticos.", "Sistemas retributivos del sector industrial.", "Soluciones y Software tecnológico."], ans: 0, exp: "El factor sociocultural es vital para adaptar el diseño de producto y el tono de la comunicación." },
    { u: "ADIPLE T4", q: "La investigación de naturaleza 'Cualitativa' destaca metodológicamente por basarse en:", opts: ["Recopilaciones masivas de encuestas estructuradas.", "Grupos reducidos y herramientas de la psicología para explorar percepciones profundas, motivaciones y frenos de compra.", "Únicamente en el procesamiento mediante inteligencia artificial.", "Las inserciones publicitarias en horario de máxima audiencia."], ans: 1, exp: "No busca la estadística, sino el 'porqué' subyacente. Ayuda a entender emociones y comportamientos complejos." },
    { u: "ADIPLE T4", q: "En el diseño de un cuestionario formal, las denominadas 'Preguntas Filtro' tienen la función de:", opts: ["Manipular los datos hacia una conclusión prefijada.", "Descartar a los sujetos que no reúnen el perfil requerido para el objeto de estudio, evitando recoger datos irrelevantes.", "Ampliar innecesariamente el volumen de la encuesta.", "Camuflar la verdadera identidad del patrocinador del estudio."], ans: 1, exp: "Aseguran que la muestra final esté compuesta exclusivamente por individuos pertenecientes al público objetivo." },
    { u: "ADIPLE T4", q: "Realizar una segmentación del mercado en base a criterios 'Psicográficos' significa clasificar a los usuarios atendiendo a:", opts: ["Su código postal o ubicación residencial.", "Sus aficiones, sistema de valores, perfil de personalidad o modelo de vida.", "Exclusivamente a su cohorte generacional o edad cronológica.", "A su titulación o nivel de estudios."], ans: 1, exp: "Permite conectar emocionalmente; por ejemplo, dirigirse a 'personas preocupadas por el medio ambiente'." },
    { u: "ADIPLE T4", q: "¿Cuál es el postulado principal de la disciplina del 'Marketing Relacional'?", opts: ["Forzar negociaciones opacas con los suministradores.", "Construir, nutrir y prolongar al máximo los vínculos de valor y confianza entre la marca y el consumidor a lo largo del tiempo.", "Fomentar el nepotismo y la contratación de vínculos familiares.", "Saturar las plataformas sociales con anuncios genéricos."], ans: 1, exp: "Prioriza la rentabilidad del 'valor del ciclo de vida del cliente' frente a la venta única transaccional." },
    { u: "ADIPLE T4", q: "En el argot del marketing, 'Posicionamiento' equivale a:", opts: ["El emplazamiento físico de la sede central.", "El lugar simbólico y los atributos emocionales que nuestra marca ocupa en el imaginario colectivo del consumidor.", "La capacidad de endeudamiento acreditada ante las entidades financieras.", "La calificación que nos otorgan las agencias externas de rating."], ans: 1, exp: "El posicionamiento es la batalla por la mente del consumidor; si piensan en deporte y piensan en Nike, ese es su posicionamiento." },
    { u: "ADIPLE T4", q: "La noción de 'Mercado Potencial' engloba a:", opts: ["La cuota de clientes fidelizados que nos compran de forma recurrente.", "El universo teórico máximo de sujetos o empresas susceptibles de requerir y adquirir nuestra categoría de producto en el futuro.", "Exclusivamente a los proveedores y distribuidores actuales.", "A los mercados internacionales emergentes no explotados."], ans: 1, exp: "Fija el techo máximo de ingresos que el sector podría generar en un escenario de penetración total." },
    { u: "ADIPLE T4", q: "El indicador de negocio conocido como 'Cuota de Mercado' expresa:", opts: ["El nivel de apalancamiento financiero o deuda soportada.", "La porción o porcentaje de ventas que absorbe nuestra marca frente al volumen total de ventas de su sector de actividad.", "Un canon fiscal aplicable a transacciones voluminosas.", "La magnitud de la plantilla contratada de forma directa."], ans: 1, exp: "Es el termómetro más fiable para saber si somos un actor dominante o secundario en nuestra industria." },
    { u: "ADIPLE T4", q: "Si hablamos del 'Macroentorno' corporativo, nos estamos refiriendo a:", opts: ["El layout interior y el clima de las oficinas de la sede.", "Las megatendencias globales y factores sistémicos (demográficos, legales, tecnológicos) que envuelven y condicionan a la totalidad del tejido empresarial.", "El panel de mando o sala de servidores de la corporación.", "La red privada formada exclusivamente por nuestros principales clientes VIP."], ans: 1, exp: "Ninguna empresa puede modificar el macroentorno; solo puede monitorizarlo y adaptarse ágilmente a sus cambios." },
    { u: "ADIPLE T4", q: "Por el contrario, ¿qué elementos conforman el 'Microentorno' de una compañía?", opts: ["Los componentes microscópicos integrados en el producto informático.", "Aquellos agentes del entorno inmediato (proveedores, competencia directa, intermediarios, clientes) que influyen en el día a día operativo.", "El conjunto de trabajadores de mantenimiento y limpieza del recinto.", "Las piezas de pequeña tornillería utilizadas en ensamblaje."], ans: 1, exp: "Las fuerzas de Porter modelan este escenario competitivo próximo donde la empresa sí tiene cierta capacidad de maniobra." },
    { u: "ADIPLE T4", q: "Para que una empresa pueda ostentar verdaderamente el 'Liderazgo en Costes', es imperativo que:", opts: ["Invierta masivamente en acabados artesanales o diseño de lujo.", "Optimice sus procesos hasta alcanzar niveles máximos de eficiencia operativa, permitiéndole operar con el coste de producción más bajo del sector.", "Despida a toda su fuerza de ventas y opere de forma automatizada.", "Restrinja sus canales de venta al entorno del comercio electrónico."], ans: 1, exp: "Es la estrategia reina de empresas como Ryanair o Ikea: máxima estandarización y control feroz de los gastos." },
    { u: "ADIPLE T4", q: "En el contexto estadístico de una encuesta, se incurre en un 'Error de Muestreo' cuando:", opts: ["Falla el soporte informático donde se almacenan las tabulaciones.", "El subgrupo de personas entrevistadas no refleja fielmente las características y proporciones de la población general que se desea investigar.", "Se extravían físicamente las hojas del cuestionario completado.", "El entrevistador se persona fuera del horario pactado."], ans: 1, exp: "Un muestreo sesgado invalida por completo cualquier conclusión que se pretenda extrapolar." },
    { u: "ADIPLE T4", q: "La disciplina corporativa del 'Branding' se define como:", opts: ["El patrocinio exclusivo de eventos gastronómicos al aire libre.", "La planificación, construcción y gestión integral de todos los activos (visuales, verbales y de reputación) que configuran la identidad de una marca.", "Las labores orientadas a la optimización del espacio logístico de almacenaje.", "El traslado físico de la sede corporativa o de los despachos."], ans: 1, exp: "El branding transforma un simple producto genérico en una entidad reconocible, dotada de personalidad y valor emocional." },
    { u: "ADIPLE T4", q: "Dentro de la política comunicativa, la rama de las 'Relaciones Públicas' (RRPP) tiene la misión fundamental de:", opts: ["Ejecutar técnicas coercitivas de cierre de ventas telefónicas.", "Cultivar y proyectar hacia el exterior e interior una imagen institucional de solvencia, prestigio y buena voluntad.", "Restringir los flujos de comunicación a la cúpula directiva.", "Organizar reuniones lúdicas o festivas de carácter privado para la gerencia."], ans: 1, exp: "Las RRPP manejan la comunicación con la prensa, la RSC y la gestión de crisis reputacionales." },
    { u: "ADIPLE T4", q: "La 'Política de Distribución' (Placement) engloba las decisiones orientadas a:", opts: ["Perfilar la estética y el diseño del packaging final.", "Garantizar que el bien o servicio esté accesible para el consumidor en el punto de venta idóneo, en el plazo requerido y en las cantidades adecuadas.", "Abonar las comisiones correspondientes a la fuerza de ventas directa.", "Uniformar y rotular la flota de vehículos comerciales de la empresa."], ans: 1, exp: "Abarca desde la logística de almacén hasta la elección entre vender en supermercados, tiendas exclusivas o mediante e-commerce." },
    { u: "ADIPLE T4", q: "Al ejecutar una 'Segmentación Conductual' o por comportamiento, estamos agrupando a los compradores en base a:", opts: ["Directrices impuestas por el departamento de recursos humanos.", "Su nivel de conocimiento, frecuencia de uso, actitud hacia la marca o momento en el que realizan la compra del producto.", "La fisionomía y morfología física de su desplazamiento motriz.", "Los resultados de evaluaciones y test psicológicos clínicos."], ans: 1, exp: "Identifica, por ejemplo, a los 'usuarios intensivos' frente a los 'compradores esporádicos'." },
    { u: "ADIPLE T4", q: "En marketing, el concepto de 'Nicho' hace referencia a un mercado:", opts: ["De dimensiones colosales y consumo masivo.", "Sumamente fragmentado, de tamaño reducido, que presenta demandas muy singulares y que suele estar desatendido por las grandes corporaciones.", "Que aboca irremediablemente al fracaso y a la quiebra de la empresa.", "Exclusivamente acotado a la comercialización de bienes suntuarios o de lujo absoluto."], ans: 1, exp: "La ultraespecialización en un nicho reduce la competencia y aumenta la lealtad y el margen de beneficio." },
    { u: "ADIPLE T4", q: "La célebre 'Matriz del Boston Consulting Group (BCG)' ubica los diferentes productos del portfolio cruzando dos variables:", opts: ["La gama cromática y el formato del packaging del producto.", "La tasa de expansión o atractivo del mercado frente a la participación o cuota relativa que la empresa ostenta en el mismo.", "La política de precios adoptada frente a la percepción de calidad del mercado.", "La edad en el mercado frente al peso logístico del artículo."], ans: 1, exp: "Esta herramienta clásica ayuda a decidir en qué productos invertir, cuáles mantener y cuáles retirar." },
    { u: "ADIPLE T4", q: "El logro de la 'Fidelización' del consumidor implica que:", opts: ["Se establezcan cláusulas penales o barreras de salida abusivas en el contrato.", "El cliente establezca un vínculo de lealtad profunda con la marca, manteniéndola como su opción preferente frente a la presión de la competencia.", "Se entregue un obsequio promocional en la primera compra.", "Se renuncie sistemáticamente al cobro de los servicios facturados."], ans: 1, exp: "La fidelidad nace de la satisfacción superlativa continuada y es el indicador más potente de la viabilidad futura del negocio." },
    { u: "ADIPLE T4", q: "En el entorno 'Business to Business' (B2B) o Marketing Industrial, el diseño del producto debe contemplar de forma crítica:", opts: ["Invertir exclusivamente en jingles o cuñas de radio convencionales.", "Un paquete integral que trascienda el equipo físico, incorporando el servicio de asistencia técnica, garantías extendidas y el mantenimiento preventivo/correctivo.", "Centrarse únicamente en el atractivo gráfico de la identidad corporativa.", "Priorizar la adquisición de componentes de bajo coste y dudosa durabilidad."], ans: 1, exp: "En la industria, una máquina que se avería para la producción; por ello, el servicio técnico es tan importante como la máquina en sí." },
    { u: "ADIPLE T4", q: "La metodología de 'Observación' en estudios de mercado puede adoptar una modalidad:", opts: ["Mecánica o presencial in situ, registrando los patrones de flujo, tiempos de permanencia o trayectorias de compra (mediante mapas de calor o conteo físico).", "Basada en avistamientos astronómicos a gran escala.", "Restringida exclusivamente al escrutinio e intromisión en los perfiles privados de redes sociales.", "Invariablemente sancionable y contraria a la ley general de defensa del consumidor."], ans: 0, exp: "Aporta información veraz sobre lo que el cliente 'hace' realmente, en lugar de lo que 'dice que hace'." },
    { u: "ADIPLE T4", q: "Se entiende por 'Marketing Social corporativo' al conjunto de estrategias destinadas a:", opts: ["La celebración sistemática de eventos y actos protocolarios de carácter social.", "La aplicación de los principios del marketing comercial para estimular, persuadir o arraigar hábitos y conductas que redunden en el bienestar colectivo de la sociedad.", "Incentivar las compras impulsivas canalizadas mediante plataformas de redes sociales.", "El mero cumplimiento de las obligaciones tributarias relativas a las cuotas de la Seguridad Social de los empleados."], ans: 1, exp: "Es el vehículo empleado por ONGs y gobiernos (ej. prevención de accidentes de tráfico o fomento de la donación de sangre)." },
    { u: "ADIPLE T4", q: "En el procesamiento estadístico de encuestas, una variable de tipo 'Discreta' es aquella que:", opts: ["Garantiza el anonimato y la estricta confidencialidad de la fuente informante.", "Únicamente asume valores enteros, siendo imposible la existencia de valores fraccionarios intermedios (ej. número de líneas de producción, unidades fabricadas).", "Se omite deliberadamente en los resúmenes ejecutivos presentados a la dirección.", "Admite cualquier valor en el espectro de los números decimales o reales continuos."], ans: 1, exp: "Es fundamental diferenciarla de las variables continuas (como el peso, el volumen o el tiempo) para aplicar las fórmulas matemáticas correctas." },
    { u: "ADIPLE T4", q: "El denominado 'Marketing de Guerrilla' cimienta su eficacia en:", opts: ["La utilización de simulaciones o arsenales balísticos inofensivos en ferias sectoriales.", "El despliegue de acciones promocionales altamente creativas, disruptivas e inesperadas, diseñadas para lograr máxima repercusión con un presupuesto mínimo.", "La focalización exclusiva de las campañas de comunicación en entornos con conflictos bélicos activos.", "El uso tradicional de grandes formatos impresos como marquesinas o lonas de gran formato."], ans: 1, exp: "Es el formato publicitario por excelencia de las pymes y startups: suplen la falta de dinero con imaginación y efecto sorpresa." },
    { u: "ADIPLE T4", q: "El concepto de 'Benchmarking' competitivo se traduce operativamente en:", opts: ["La asignación de plazas o bancos en las zonas de descanso de la empresa.", "El proceso estructurado de auditoría, comparación y asimilación de los métodos y estándares de excelencia practicados por los líderes indiscutibles del mercado.", "La copia no autorizada y el plagio de patentes o diseños industriales resguardados.", "La maniobra agresiva orientada a la expulsión de firmas competidoras del sector de actividad."], ans: 1, exp: "No es copiar, sino aprender y adaptar inteligentemente las mejores prácticas de la industria a la propia realidad corporativa." },
    { u: "ADIPLE T4", q: "A la hora de elaborar la matriz DAFO, los cuadrantes correspondientes a 'Fortalezas' y 'Debilidades' reflejan variables de naturaleza:", opts: ["Exclusivamente originadas en el entorno exógeno a la organización.", "Estrictamente endógena o interna a la organización, sobre las cuales la dirección posee potestad y capacidad de modificación.", "Limitadas únicamente a los estados financieros y flujos de tesorería.", "De orden puramente emocional y perceptivo en relación al estado de ánimo de los mandos."], ans: 1, exp: "Todo lo que la empresa 'ES' o 'TIENE' actualmente se clasifica como interno (Debilidad o Fortaleza)." },
    { u: "ADIPLE T4", q: "En el análisis macroeconómico PESTEL, el epígrafe 'T' evalúa el impacto de:", opts: ["Las variaciones climáticas y el parte del tiempo meteorológico a corto plazo.", "El entorno Tecnológico: nivel de obsolescencia, disrupciones digitales, robótica, IA e inversión en I+D.", "Las infraestructuras de Transporte público en las inmediaciones del parque empresarial.", "El Tamaño y volumen de facturación de las principales corporaciones del país."], ans: 1, exp: "Un salto tecnológico puede dejar obsoleto todo un sector de la noche a la mañana." },
    { u: "ADIPLE T4", q: "El principio de Objetividad en la investigación de mercados exige de manera ineludible:", opts: ["Que sea la cúpula directiva quien determine qué datos deben ser resaltados y cuáles suprimidos.", "Que todo el proceso de recopilación, tabulación e interpretación se realice con máximo rigor analítico, desprovisto de sesgos, intuiciones personales o presiones corporativas.", "Que el estudio prescinda completamente de los testimonios humanos, centrándose solo en entes físicos.", "Que el presupuesto adjudicado al estudio sea extremadamente austero y limitado."], ans: 1, exp: "Si el investigador manipula los resultados para 'contentar al jefe', el estudio pierde todo su valor diagnóstico." },
    { u: "ADIPLE T4", q: "Dentro del diseño logístico, un 'Canal Largo de Distribución' se caracteriza por:", opts: ["Cubrir una distancia kilométrica excepcionalmente extensa entre la planta productiva y el almacén.", "La intermediación de múltiples eslabones (tales como importadores, mayoristas, distribuidores zonales y minoristas) entre el punto de origen y el consumidor final.", "Experimentar unos plazos de tránsito y entrega que superan con creces el ciclo natural de un año fiscal.", "Operar de manera exclusiva a través del canal digital, obviando la presencia en el entorno físico de retail."], ans: 1, exp: "Es imprescindible para aquellos productos de gran consumo que necesitan estar presentes en cientos de miles de puntos de venta distintos." },
    { u: "ADIPLE T4", q: "En la planificación comercial, la fase de 'Targeting' o selección de público objetivo consiste en:", opts: ["Diseñar y delimitar físicamente las dianas empleadas en los campos de tiro profesionales.", "Analizar el atractivo de cada uno de los segmentos previamente identificados y escoger aquellos a los que la compañía orientará toda su ofensiva de marketing.", "Confeccionar los listados generales de precios o catálogos tarifarios actualizados.", "Ejecutar la contratación, integración y adiestramiento inicial de la fuerza de ventas directa."], ans: 1, exp: "Tras segmentar, la empresa debe elegir con inteligencia dónde es más fuerte y dónde el mercado es más rentable (targeting)." },
    { u: "ADIPLE T4", q: "El concepto industrial de 'Obsolescencia Programada' se fundamenta en:", opts: ["Una rotura accidental e impredecible surgida durante el uso cotidiano de un dispositivo tecnológico.", "La decisión de ingeniería de limitar artificialmente la vida útil del producto, forzando un fallo prematuro que induzca a un nuevo ciclo de compra.", "La reconfiguración y actualización del código de los autómatas programables en las líneas de ensamblaje.", "La asignación planificada de los calendarios vacacionales del personal adscrito al área de mantenimiento."], ans: 1, exp: "Ha sido la base del consumo de masas de muchos productos electrónicos, aunque hoy en día es fuertemente perseguida por las normativas medioambientales." },
    { u: "ADIPLE T4", q: "Un entorno competitivo que recibe la denominación de 'Mercado Saturado' es aquel en el que:", opts: ["Las precipitaciones meteorológicas y el nivel de humedad dificultan la operativa logística ordinaria.", "El volumen global de oferta ha colapsado o sobrepasado a la capacidad real de demanda, impidiendo un crecimiento natural y levantando inmensas barreras a la entrada de nuevas empresas.", "Ningún participante es capaz de concretar operaciones de venta o alcanzar el punto de equilibrio.", "La intervención estatal provee directamente y sin coste la totalidad de los bienes y servicios esenciales a la ciudadanía."], ans: 1, exp: "Sectores como la telefonía móvil en países desarrollados son claros ejemplos de saturación total." },
    { u: "ADIPLE T4", q: "Previamente al lanzamiento de una investigación, la implementación de un 'Pretest o Cuestionario Piloto' tiene como objetivo central:", opts: ["Recabar de forma exclusiva la opinión del personal de cabina y vuelo en el sector aeronáutico.", "Someter el instrumento de medida a una prueba de campo acotada, al objeto de afinar la redacción, corregir ambigüedades y verificar el flujo lógico de las preguntas.", "Ejecutar un sondeo de opinión superficial y veloz destinado a los perfiles corporativos en redes sociales.", "Funcionar como método de criba para la contratación del personal destinado a las labores de campo."], ans: 1, exp: "Evita el riesgo inasumible de lanzar miles de encuestas que los usuarios no van a comprender correctamente." },
    { u: "ADIPLE T4", q: "La mecánica operativa del denominado 'Marketing Viral' aprovecha principalmente:", opts: ["Las redes de distribución hospitalaria, el suministro de productos sanitarios y la trazabilidad de vacunas.", "La hiperconectividad de las plataformas digitales, logrando que sea el propio usuario quien, seducido por la originalidad del mensaje, actúe de forma entusiasta como difusor del mismo ante su círculo social.", "La contratación masiva de inserciones o faldones publicitarios en las cabeceras de prensa escrita tradicional.", "El arrendamiento de emplazamientos físicos superlativos, como lonas en fachadas completas de inmuebles urbanos."], ans: 1, exp: "Consigue una visibilidad y un impacto astronómico con una inversión en difusión cercana a cero." },
    { u: "ADIPLE T4", q: "En la ortodoxia de las 4P's, la variable 'Producto' trasciende el mero artículo e integra elementos como:", opts: ["El hardware físico o artefacto aisladamente considerado, excluyendo el resto de su ecosistema.", "El núcleo central del bien junto a atributos periféricos vitales como el packaging, la notoriedad de marca, las coberturas de garantía y la excelencia del servicio técnico postventa.", "El componente monetario que determina el desembolso o precio tarifario asignado al mismo.", "Las infraestructuras físicas de retail (puntos de venta) donde el usuario acude para adquirir y abonar su compra."], ans: 1, exp: "Un smartphone no es solo cristal y chips, es el estatus de la marca, la app store y el soporte técnico." },
    { u: "ADIPLE T4", q: "Dentro del modelo de diagnóstico PESTEL, el vértice etiquetado con la inicial 'E' hace referencia a:", opts: ["Las infraestructuras de suministro y consumo de Energía renovable de la entidad corporativa.", "Las fuerzas Económicas sistémicas de la región o país (como las tasas de interés, el IPC, los ciclos de recesión o la estructura del empleo).", "La tasa de matriculación en los niveles superiores de Educación universitaria.", "Las variables estéticas referentes al Estilo de diseño de las campañas promocionales o el escaparate digital de la corporación."], ans: 1, exp: "Un entorno económico en crisis obliga a la empresa a adaptar su oferta, apostando por bienes de primera necesidad o líneas 'low cost'." },
    { u: "ADIPLE T4", q: "En el argot del diseño y la comunicación corporativa, el 'Logotipo o Logo' es conceptualizado como:", opts: ["Una mascota animada o animal empleado para amenizar los eventos y congresos de carácter comercial organizados por la firma.", "La conjunción de elementos gráficos, tipográficos y cromáticos que actúa como el sello distintivo y la firma visual e irrepetible de una marca o institución mercantil.", "El formato y registro lingüístico predefinido que el portavoz de la corporación adopta al intervenir ante la junta general de accionistas o las cámaras de televisión.", "La reproducción del autógrafo o firma hológrafa del director general de la compañía impresa en el reverso de la documentación oficial."], ans: 1, exp: "Debe ser simple, escalable, memorable e inmediatamente reconocible en cualquier soporte y país." },
    { u: "ADIPLE T4", q: "Si hablamos de 'Diversificación Conglomerada', nos estamos refiriendo a una estrategia expansiva donde la organización empresarial:", opts: ["Profundiza en la penetración de mercado incrementando la intensidad promocional sobre su catálogo y oferta de artículos histórica y consolidada.", "Invierte sus excedentes de capital para introducirse en sectores industriales, tecnologías o mercados de consumo que no guardan relación de sinergia alguna con el núcleo duro de su actividad original.", "Establece tablas de puntuación para ponderar la eficacia del modelo comercial de la competencia directa en su mercado de actuación.", "Orquesta la fusión jurídica, por absorción o integración recíproca, de dos sociedades anónimas con modelos de negocio completamente idénticos."], ans: 1, exp: "Minimiza el riesgo global (si cae un sector, se sostiene con otro), aunque supone una complejidad enorme de gestión corporativa." },
    { u: "ADIPLE T4", q: "El fenómeno conductual etiquetado por el retail como 'Showrooming' describe la situación en la que el usuario:", opts: ["Se encarga de mantener impecable y ordenado el espacio del establecimiento o las vitrinas destinadas a la exhibición comercial.", "Acude al establecimiento físico para informarse, palpar e interactuar con el artículo, para acto seguido abandonar la tienda y formalizar la compra a través del canal digital buscando una oferta o precio inferior.", "Desfila o presenta los prototipos de productos a la red de distribuidores de forma exclusiva.", "Instala su domicilio o residencia habitual de manera permanente en el interior de una nave industrial o en dependencias del complejo de oficinas corporativo."], ans: 1, exp: "Para frenarlo, las tiendas físicas están optando por ofrecer experiencias, asesoramiento premium y servicios exclusivos en el propio punto de venta." },
    { u: "ADIPLE T4", q: "Al diseñar una investigación cuantitativa de mercados, ¿qué definición técnica se otorga al concepto de 'Universo' o población general?", opts: ["La inmensidad inabarcable del entorno astronómico y los cuerpos celestes.", "La agrupación exhaustiva de todos y cada uno de los entes, individuos, agrupaciones familiares o corporaciones susceptibles de requerir y encajar con los parámetros de nuestro estudio comercial.", "La suma aritmética de todas las empresas multinacionales o de gran capitalización en funcionamiento a lo largo de los cinco continentes.", "De manera exclusiva y limitativa, a las corporaciones rivales o competencia directa que disputa a diario la hegemonía comercial del sector en liza."], ans: 1, exp: "El Universo es el todo; la Muestra es la pequeña porción representativa que se extrae para ser encuestada." },
    { u: "ADIPLE T4", q: "Un artículo o bien de consumo amparado bajo la definición de 'Marca Blanca' o Marca del Distribuidor es aquel que:", opts: ["Carece de pigmentación en el diseño de su embalaje o packaging primario exterior, resultando este de color absolutamente monocromo e incoloro.", "Es elaborado o envasado bajo el distintivo comercial y los protocolos de la gran superficie minorista que lo comercializa (por ejemplo, Aliada o Hacendado), posicionándose frecuentemente con un precio de venta más ajustado.", "Vulnera el ordenamiento jurídico al constituir una infracción sobre los derechos de la propiedad intelectual y ser categorizado como producto ilícito o de contrabando en la legislación vigente.", "Hace alusión, de forma exclusiva, al revestimiento con pinturas aislantes o compuestos plásticos de alta blancura sobre muros y cierres industriales."], ans: 1, exp: "Representan una cuota altísima de la cesta de la compra y basan su poder en la distribución extensiva del supermercado." },
    { u: "ADIPLE T4", q: "La estructura conceptual y argumental de la 'Propuesta de Valor' de la organización se articula para responder de forma diáfana y contundente a la siguiente interrogante formulada tácitamente por el mercado:", opts: ["¿A cuánto asciende el importe que deberé desembolsar en caja para adquirir el artículo?", "¿Qué motivos racionales y emocionales avalan la decisión de confiar en nosotros y en nuestro producto frente a la multiplicidad de alternativas y sustitutivos existentes en el sector de la competencia?", "¿En qué latitud o polígono logístico concreto se ubica el centro productivo responsable de la elaboración del equipo?", "¿Quién ejerce el liderazgo gerencial en la empresa o firma los comunicados institucionales de la misma en prensa o medios oficiales?"], ans: 1, exp: "Debe ser el faro que guía a la empresa y el mensaje clave que el cliente percibe en cuestión de pocos segundos." },
    { u: "ADIPLE T4", q: "En la taxonomía del comercio digital o e-commerce, el acrónimo B2B (Business to Business) alude invariablemente a:", opts: ["Las transacciones y procesos de intermediación, provisión y suministro comercial establecidos desde la corporación industrial hacia el cliente o consumidor particular final (doméstico).", "Las dinámicas operativas de integración, provisión de materias primas o de prestación de servicios técnicos estandarizados canalizadas a través de plataformas electrónicas y desarrolladas exclusivamente entre organizaciones empresariales.", "El flujo de facturación por adjudicaciones derivado directamente desde las entidades del sector público hacia el tejido empresarial privado que abastece de servicios y obras o dotación a las distintas administraciones.", "Al intercambio lúdico o altruista de bienes y enseres desarrollado entre el entorno familiar y amistades que operan al margen del ámbito legal societario y empresarial establecido por el derecho civil."], ans: 1, exp: "Sus procesos de compra son mucho más largos y racionales que en el mercado de gran consumo." },
    { u: "ADIPLE T4", q: "Al ejecutar la herramienta de diagnosis PESTEL, la letra 'L' del acrónimo nos conmina a auditar y calibrar el impacto de:", opts: ["Las directrices y exigencias operativas derivadas de las operaciones y flujos logísticos de movimiento, expedición, flete, almacenamiento o suministro regular de las cadenas internacionales del proceso de producción material.", "Todo el bloque del entorno Legislativo y jurídico-legal: regulaciones, normativa sobre contratos laborales, código mercantil, legislación antitrust, ley de protección al consumidor y de control de los datos del entorno cibernético.", "Las directivas referidas al cumplimiento innegociable de los planes maestros en relación a la higienización general y la desinfección preventiva del parque industrial.", "Las directrices cualitativas asociadas y la medición del grado de liderazgo y el perfil carismático ostentado de manera ineludible por el cuadro gerencial de máxima jerarquía."], ans: 1, exp: "Las normas cambian y afectan dramáticamente al negocio: impuestos, homologaciones, etiquetados o normativas contra emisiones de gases perjudiciales." },
    { u: "ADIPLE T4", q: "La metodología analítica descrita como 'Segmentación por Ventajas Buscadas' centra el foco de su clasificación del mercado apoyándose en:", opts: ["Variables de corte exclusivamente sociodemográficas centradas en clasificar, geolocalizar y encasillar los patrones del distrito o código postal del hábitat y entorno de confort del consumidor evaluado de modo superficial.", "Las expectativas más profundas del usuario y el nivel o la tipología de beneficios reales o de soluciones precisas, palpables e intangibles, que el mismo exige obtener en el proceso y dinámica de su acto de compra en las superficies comerciales.", "Datos de naturaleza biométrica relativos a variables de clasificación estricta de la madurez y nivel cronológico asociado a la fecha del nacimiento biológico y la identificación o identidad de género del mismo.", "Información y datos estadísticos de carácter clínico en lo relativo a la evaluación y diagnosis paramétrica de la identidad, identidad sexual biológica, psique u otro rasgo relativo al historial genético del mercado."], ans: 1, exp: "Reúne a las personas en torno al problema real que desean resolver (ej. los que compran dentífrico para tener 'dientes blancos' vs 'encías sanas')." },
    { u: "ADIPLE T4", q: "Dentro de la nomenclatura estratégica asociada a la matriz del Boston Consulting Group, el rol y protagonismo de un 'Producto Interrogante (Dilema)' obedece a un artículo del catálogo que:", opts: ["Constituye un auténtico y rotundo misterio inescrutable ante el mercado y su público, al carecer por completo de planes formales y una correcta definición técnica e industrial de sus componentes o prestaciones básicas.", "Atraviesa una fase de desarrollo crítico donde ostenta un escaso dominio de cuota relativa o competitividad en un contexto sectorial que, por contraposición, experimenta ritmos fulgurantes de crecimiento, inyectando un nivel de elevado riesgo corporativo.", "Pertenece a líneas del catálogo general de enorme madurez corporativa, que históricamente ha generado altos beneficios y representa a día de hoy la insignia del pasado.", "Se caracteriza de modo inexcusable y flagrante por no tener un etiquetado identificativo de los componentes a causa de un error legal no subsanable durante la trazabilidad general industrial de la manufactura y proceso o ensamblaje."], ans: 1, exp: "Es una apuesta arriesgada: si se le inyecta mucho dinero y talento puede acabar siendo la 'Estrella' de la empresa, pero también puede fracasar y ser descartado." },
    { u: "ADIPLE T4", q: "La técnica de comercialización de mayor y probada rentabilidad conocida mundialmente bajo las siglas de 'Cross-selling' o Venta Cruzada consiste sistemáticamente en:", opts: ["Desarrollar el discurso y acto transaccional con una acusada animadversión, frustración personal o visible grado de hostilidad o enojo hacia el cliente.", "Sugerir e inducir de manera inteligente e integrada la incorporación, al proceso de checkout y a la cesta activa del cliente final, de productos o servicios complementarios directamente relacionados y lógicos al bien central elegido y preseleccionado.", "Ceder y claudicar en la transacción comercial para redireccionar voluntariamente el volumen de ventas e ingresos directamente hacia el ecosistema de la competencia empresarial más belicosa o de proximidad.", "Sustituir de manera sorpresiva y alevosa el artículo original de adquisición por una copia o mercancía con unas especificaciones diametralmente contrarias a la premisa original preestablecida por parte y encargo del contratante final."], ans: 1, exp: "La recomendación 'los usuarios que compraron este teléfono también se llevaron esta carcasa protectora' dispara el margen comercial global por ticket." },
    { u: "ADIPLE T4", q: "La jurisdicción comercial y civil del derecho aplicable define y tipifica la 'Publicidad Engañosa' con gran rigor sancionador al considerarla aquella práctica que:", opts: ["Gozando de enorme impacto, notoriedad y alta repercusión mediática en medios convencionales, basa su enfoque y guion estratégico en una retórica dotada de acentuado humorismo, sarcasmo fino y una creatividad deslumbrante en todas sus cuñas sonoras y gráficas.", "Trastoca, manipula gravemente, tergiversa y oculta deliberadamente y a sabiendas elementos esenciales y atributos centrales que conforman el bien, con una clara vocación e intencionalidad dolosa para pervertir la capacidad de raciocinio y elección del ciudadano.", "Prescinde por completo del espectro de colores, apostando decididamente por una propuesta minimalista, estática, acromática y altamente sofisticada o de diseño vintage y alternativo en el plano publicitario del mercado saturado y competitivo actual.", "Abarata notablemente, con gran margen en costes, y exime de obligaciones tributarias complejas al departamento de diseño creativo mediante un modelo publicitario con la utilización del papel periódico o flyers informales fotocopiados y buzoneados de bajo estándar y rango."], ans: 1, exp: "Genera falsas expectativas que, de ser descubiertas por el cliente o los organismos reguladores, erosionan irreparablemente el capital social o imagen de marca." },
    { u: "ADIPLE T4", q: "Bajo la óptica corporativa internacional, el concepto de 'Mercado Global' implica una visión expansiva y universal donde la directiva y gerencia empresarial:", opts: ["Circunscribe deliberadamente, limitando con medidas coercitivas los envíos comerciales para concentrar toda su actividad de explotación de modo enclaustrado a las fronteras administrativas y pedanías de un municipio muy reducido o recóndito.", "Elimina fronteras y barreras físicas considerando en esencia al panorama mundial al completo y su base de miles de millones de pobladores como su zona lógica y lícita de expansión económica y la extensión idónea o marco potencial para colocar sus productos finales.", "Recurre e implementa únicamente, a nivel logístico, a la utilización de aerostáticos o flotas de globos zepelín para los tránsitos y publicidad de los bienes físicos comercializables y la cobertura de los servicios técnicos a sus franquiciados a baja cota aerodinámica.", "Maneja una cuota de penetración corporativa absolutamente hegemónica en todos los continentes y paralelos donde el tejido competitivo adverso y rival ha quedado asfixiado y finiquitado con la creación legal de un cártel blindado a nivel internacional o de comercio de aranceles globales."], ans: 1, exp: "Las herramientas del e-commerce moderno dotan de capacidad logística y escaparate global a pequeñas empresas de manufactura local y tradicional para comercializar en cualquier punto de los continentes de forma directa o triangulada." },
    { u: "ADIPLE T4", q: "En la infraestructura técnica y arquitectónica de sistemas corporativos, la herramienta tecnológica denominada 'CRM' (acrónimo de Customer Relationship Management) opera vitalmente como:", opts: ["Una aplicación para automatizar líneas mecánicas destinadas a moldear y embutir planchas, fresar perfiles y controlar servomotores industriales de precisión o de torneado CNC mediante planos renderizados o algoritmos CAD.", "Un software, ecosistema digital integral y modelo estratégico diseñado de modo específico para orquestar de forma trazable e interactiva las comunicaciones y el archivo de datos provenientes de la experiencia comercial, los incidencias postventa e histórico y del ciclo de vida general del cliente en la firma mercantil.", "Un desarrollo puramente aritmético cuyo designio fundamental y núcleo es computar matemáticamente el devengo, aplicar las retenciones IRPF u organizar el cuadrante logístico de las altas o bajas del pago puntual de la contraprestación pecuniaria laboral.", "Un entretenimiento programado por la unidad informática que dispone de un simulador virtual renderizado orientado exclusivamente al ocio particular y el esparcimiento o descanso neuronal de los ingenieros entre sus largos turnos en salas blancas corporativas informáticas u hot desking."], ans: 1, exp: "Permite una gestión personalizada real, centralizando el histórico de emails, llamadas, ventas e insatisfacciones de cada usuario al que accede cualquier perfil del engranaje empresarial corporativo en un solo click del dashboard digital." },
    { u: "ADIPLE T4", q: "La pauta de tarificación estratégica y pionera tipificada con el epígrafe de 'Estrategia de Descremación de Precios', utilizada con altísima frecuencia, consiste y se estructura a lo largo del cronograma de lanzamiento al dictaminar de modo taxativo que:", opts: ["Se procede a la comercialización mayorista estricta en el segmento agroalimentario al canal HORECA, concentrando el modelo en exclusiva sobre mercancía relacionada con derivados de la producción, cría e importación láctea natural o ultra pasteurizada.", "La presentación del artículo en el mercado debe ir acompañada de una elevadísima e intimidante prima en el precio inicial de la etiqueta, con el objetivo exclusivo de captar la renta disponible superior y maximizar los beneficios en el escaso margen de tiempo de la fase incipiente inicial o early adopters para, finalmente, aplicar sucesivos y paulatinos descuentos, abaratando o popularizando la tarifa con objeto y finalidad de alcanzar de facto al resto de las masas.", "La política y doctrina inquebrantable radique invariablemente en deflactar hasta mínimos históricos en los costes al presentar al público el catálogo, operando a riesgo e incluso con márgenes contables fuertemente negativos, con el objeto irrenunciable e irrecuperable en un primer asalto corporativo de ganar cuota mediante estrangulamiento comercial sobre los operadores o competidores adyacentes de un modo implacable.", "La distribución masiva en el segmento retail se efectúe o se orqueste en modalidad netamente gratuita con un muestreo intensivo del producto definitivo en formato tester físico, a título puramente de compensación, fidelización no exigible de tipo caritativo o como donación filantrópica general."], ans: 1, exp: "Es el modelo adoptado por gigantes como Sony, Microsoft o Apple. Se obtiene gran margen inmediato por la novedad tecnológica superior y más tarde los excedentes se reubican con precios progresivamente rebajados de penetración hacia mercados más sensibles a la economía familiar." },
    { u: "ADIPLE T4", q: "Cuando a la conclusión o cierre de los estados o previsiones a largo plazo del marketing los estudios revelan e identifican la cristalización del indicador vital que llamamos 'Lealtad a la Marca' es debido a y se ratifica invariablemente mediante la certeza estadística de que el cliente o comprador:", opts: ["Procede a la adquisición impulsiva y alocada de forma irreprimible de las referencias expuestas en lineales perimetrales o expositores y que de un modo casual o arbitrario logran captar ocasional y periféricamente su primera impresión visual, de diseño o la cromática externa en ese ínfimo momento decisional aleatorio de visita.", "Reitera y refrenda con sus compras periódicas, la predilección absoluta por las garantías prestacionales que la organización le aporta en los bienes ofertados de la marca elegida, manifestando y ratificando una total adhesión al rehusar sistemáticamente dejarse seducir o migrar y transferir la confianza hacia artículos o catálogos y referencias alternativas que la encarnizada rivalidad económica de la competencia adyacente propone, de forma seductora e invasiva a lo largo y ancho del mercado saturado.", "Paraliza por completo y se abstiene forzosamente de realizar cualquier acción de aprovisionamiento o demanda, abandonando para siempre la necesidad básica del segmento comercial de manera absoluta y pasando a una total inanición mercantil.", "Efectúa, de forma metódica y estructurada en todas sus interacciones mediante cauces de servicio postventa o buzón legal, reiteradas exigencias infundadas, expedientes de reclamación formal, protestas públicas o amenazas institucionales y procedimentales continuas y contumaces a lo largo de los periodos impositivos trimestrales de ejercicio comercial."], ans: 1, exp: "Este hito supone la cima de la relación comercial exitosa y la creación del principal activo refugio, un vínculo fuertemente emocional donde el usuario ejerce de verdadero evangelizador corporativo frente a posibles competidores u opiniones." },
    { u: "ADIPLE T4", q: "Durante el proceso de la monitorización con rigor estricto del método de la diagnosis del contexto externo corporativo con el popular PESTEL, el epígrafe identificado y pautado habitualmente con la vocal 'E' (por la terminología 'Ecológica' de matriz o base) atañe irremediablemente y examina, documenta o anticipa con enorme escrutinio:", opts: ["Las doctrinas, teorías estructuralistas corporativas o pautas relativas al ahorro y economía monetaria de la escala financiera de contención severa y exhaustiva que el equipo técnico impone o de las reservas y saldos o recortes internos proyectados meticulosamente al máximo céntimo presupuestario para blindar un balance sin fisuras al cierre del semestre.", "El voluminoso corpus de exigencias e imperativos normativos en materia legal que salvaguardan la integridad del biotopo medioambiental, dictaminan y supervisan la viabilidad real o de obsolescencia de modelos de negocio por cambios en los perfiles macro climáticos globales o abordan un marco de penalizaciones asociadas, junto a los estrictos y progresivos estándares y requisitos en la obtención de trazabilidad verde en el plano de la sostenibilidad ecológica de toda actividad vinculada de índole industrial.", "La gradación cromática exterior y el manual de los diseños ergonómicos o identidades estéticas predominantes y las normativas y codificación corporativa interna oficial en relación a las pinturas en resina acrílica, epoxídica e imprimación en la sala y cadena de los talleres en relación a los componentes o perfiles y el mecanizado en el catálogo y maquinaría robótica estandarizada automatizada en el interior de las plantas integradas del complejo corporativo.", "Las guías preventivas para protocolos y estándares de limpieza en profundidad en la asepsia personal estandarizada aplicables obligatoriamente o los exhaustivos rituales orientados a los recursos humanos que de modo ineludible o inexcusable todo individuo debe cursar mediante su adscripción legalizada y firma al estamento corporativo para prevenir incidencias en entornos higiénicos muy estrictos o biológicos."], ans: 1, exp: "Cada ejercicio corporativo está más fuertemente impactado por aranceles frente a altas tasas de huella y emisiones de CO2 generadas o el encarecimiento exponencial e incesante relativo o los embargos derivados por no respetar las certificaciones obligatorias vigentes en normativas medioambientales del reciclamiento o su recuperación y fin del ciclo y vida integral obligatoria." },
    { u: "ADIPLE T4", q: "Depender estructuralmente de la colaboración exclusiva que denominamos en terminología logística de la industria 'Proveedor Único' implica de modo inexorable que nuestra firma comercial:", opts: ["Obtiene y blinda en los libros contables una enorme disminución o abaratamiento total de sus partidas por transporte internacional garantizando siempre el flete íntegro global a cero euros mediante subvención cruzada garantista total vitalicia de aprovisionamiento regular incondicional perpetuo de componentes.", "Asume y concentra toda su exposición a una vulnerabilidad técnica insoslayable con altas contingencias críticas derivadas por un claro incremento exponencial inasumible relativo al peligro ante una situación dramática e inviable si hubiere que forzar o presionar bajo negociación alguna a la contraparte; en el extremo fatal, puede abocar o acarrear paralizar y quebrar toda la manufactura global del entramado operativo completo del recinto propio si las matrices remotas reportan disfuncionalidades, cortes en suministro, huelgas encubiertas y alzamiento arbitrario ilícito de precios sin capacidad real de reacción organizativa corporativa inmediata sustitutiva para el tejido fabril nuestro.", "Dispone ante la cámara o en el frente competitivo adverso o panel regulatorio un argumento publicitario inmejorable y que posiciona en exclusiva ante cualquier inversor especulativo internacional una clara e infranqueable e invulnerable ventaja frente al resto de oponentes al demostrar perfiles integrales.", "Minimiza la necesidad del departamento responsable interno delegando esa figura ejecutiva hacia otros equipos y extingue la preocupación de control al pasar a un segundo escalón irrelevante cualquier tema referente al almacenado o en su stock preventivo de contingencias por caducidad no teniendo el impacto material económico sobre la toma macro direccional a alto nivel general corporativo en la agenda programática semanal ordinaria."], ans: 1, exp: "Delegar o focalizar toda la fabricación delegando subconjuntos irremplazables al amparo y buena fe o destreza de un monopolio distribuidor de exclusividad pone en claro jaque y secuestro o al borde de un precipicio insalvable a los ritmos y objetivos logísticos preestablecidos o la capacidad e independencia técnica decisional de las propias y costosas líneas automatizadas del fabricante principal si la contraparte quiebra, sufre siniestros críticos mayores o se torna manifiestamente abusiva y de un chantaje extorsionador económico inaceptable de modo brusco e imprevisto." },
    { u: "ADIPLE T4", q: "La especialización o modalidad estratégica designada y documentada con la palabra 'Merchandising' dentro de la táctica publicitaria corresponde propiamente a:", opts: ["Mecanismos coactivos para gestionar los protocolos en las tareas ejecutivas desarrolladas a lo largo y ancho en la sede y estancia VIP que alberga diariamente los despachos acristalados integrados destinados a las direcciones gerenciales o el mando de dirección intermedio en las dependencias acotadas ejecutivas de la corporación empresarial.", "El conjunto articulado, coordinado, sensorial y persuasivo de micro tácticas o de estímulo e incentivo comercial de acciones psicológicas o estéticas orquestadas o planificadas con enorme meticulosidad para, desarrolladas a nivel y pie del establecimiento presencial o punto último final de adquisición directa y venta interactiva, conseguir que se canalicen alzas palpables directas e inducidas orientadas con fuerza en maximizar e incentivar a potenciar la demanda y ratios reales de rentabilidad volumétrica (por ejemplo mediante disposición intencionada al detalle del flujo zonal, impactos sonoros inmersivos orientados o exhibidores iluminados específicos o cartelería promocional muy dirigida sobre góndolas).", "La sistematización exclusiva enfocada operativamente a coordinar en origen o ruta del traslado perimetral rodado logístico terrestre en flotas integradas en plataformas de remolque TIR hacia áreas y grandes macro puertos para grandes importaciones u optimizar o abaratar peajes logísticos aplicados a bienes y mercancías a bordo por toda la península continental.", "La configuración formal técnica orientada y enfocada al ordenamiento civil arquitectónico urbanístico que aborde, supervise, diseñe los planos de planta y supervise de inicio la distribución o los muros acotados y pavimentos e instalaciones perimetrales operativas completas necesarias o licencias aplicables antes y para asentar legalmente fábricas de industria o naves en el perímetro exterior perimetral de un parque empresarial exterior de expansión periférica."], ans: 1, exp: "Engloba la gestión racional, sensitiva y visual del punto de contacto para hacer más placentero el proceso de compra; abarcando disciplinas relativas al ordenamiento, iluminación, ritmo musical y temperatura para incitar e inducir y desencadenar o decantar el impulso transaccional definitivo subconsciente latente a nivel subliminal de un individuo potencial en el instante crítico previo decisivo." },
    { u: "ADIPLE T4", q: "La poderosa y ampliamente validada matriz del experto internacional y teórico Porter orienta a los equipos ejecutivos a:", opts: ["Determinar o configurar y negociar márgenes de beneficio tendentes a establecer tarifas a saldo que no rebasen costes orientando al cliente a liquidaciones por infra precio que desvirtúen o erosionen irreversible y de modo general o abaraten su prestigio frente al gran canal minorista por la saturación forzada incontrolada para eliminar el stock general o inventariado latente.", "Dilucidar y diagnosticar o establecer con exactitud y anticipación una ventaja competitiva o pauta para plantar cara a la beligerancia del mercado frente a la ofensiva y encarnizada rivalidad sectorial e intensidad de las empresas limítrofes afines con objeto y garantía de amarrar una cuota de permanencia y posición ventajosa rentable con proyección sostenible o blindaje en la evolución general estratégica corporativa temporal de crecimiento y defensa consolidada a medio plazo integral.", "Decidir o concretar con suma precisión en qué perfil laboral debe enfocarse, instruir o decantar operativamente el esfuerzo con los programas selectivos y de criba en captación para sumar personal al departamento de administración.", "Ejecutar balances para liquidar gravámenes para abonar y tributar fiscalidad y exenciones de una forma o bajo las auditorías más estrictas establecidas de la agencia del estado o la administración central local del mercado nacional para saldar deuda pública obligatoria o aplazar cargos recurrentes impositivos en libros normativos correspondientes institucionales requeridos."], ans: 1, exp: "El modelo determina cómo la empresa debe combatir competitivamente: mediante menores costes de manufactura, añadiendo gran diferencial o mediante especialización; pero no le dice cómo administrar la gestión financiera fiscal ni le instruye o recomienda regalar el producto bajo pautas ajenas desleales ruinosas irresponsables e irrecuperables en su margen industrial o productivo de su segmento u horizontal generalizado o local específico." },
    { u: "ADIPLE T4", q: "Cuando un anunciante emplea y articula operativamente el 'Sponsoring' o la esponsorización corporativa y técnica conocida popularmente en nuestro idioma bajo el vocablo de Patrocinio se trata de:", opts: ["Erigirse o designarse en el máximo organigrama y representante formal institucional asumiendo directamente la delegación directiva gerencial total con voto de control indiscutido al situarse a la cabeza del poder máximo ostentando o concentrando todo mandato, de mando, representación fáctica legal e influencia del consejo del holding ejecutivo de accionariado o directorio general administrativo máximo decisional único superior a cualquier instancia previa y general.", "Vincular y proporcionar músculo financiero económico o recursos materiales, logísticos y tecnológicos a un ente independiente organizativo, colectivo o una figura con alto prestigio y enorme exposición pública para lograr y obtener a cambio y sinergia positiva una visibilidad directa publicitaria del nombre de marca, que potencie al asociar, emparejar o permear o impregnarse en el imaginario popular o del usuario de los inestimables y poderosos valores reputacionales, éticos, del afán de sacrificio y éxito que transmite intrínseca y unánimemente el receptor patrocinado al cliente frente y respecto a toda la opinión de la gran audiencia global potencial difusora del mensaje latente subyacente de respaldo proyectado al aire en los certámenes televisivos de alto calibre o eventos y celebraciones y espectáculos masivos populares afines y paralelos.", "Efectuar, orquestar o programar la toma de control accionarial o absorción mercantil integral adquiriendo de modo directo bajo oferta opaca perimetral mediante un proceso legal hostil o en su caso con negociación o por suma de pasivos y derechos un modelo de pequeña entidad del segmento empresarial marginal para diluir la amenaza y eliminar la pluralidad a bajo precio extinguiendo y consolidando la base industrial absorbida.", "Ceder y entregar operativamente todo el peso de comercialización del catálogo hacia operadores franquiciados mayoristas y un complejo canal con múltiples e incontrolables intermediarios ciegos donde las políticas restrictivas aplicadas no consienten operar ni establecer nunca redes e infraestructuras directas minoristas para los envíos corporativos de pedidos."], ans: 1, exp: "Con la aparición o sobreimpresión, y mediante estampación en los monoplazas, motocicletas o dorsales en torneos, campeonatos mundiales o actos culturales, la firma asume de inmediato una aureola que transfiere la pasión del fan incondicional hacia su propia marca de modo masivo global con un enorme calado sin fronteras lingüísticas en la conciencia del observador pasivo directo espectador final que es el target principal deseado directo potencial o real receptor." },
    { u: "ADIPLE T4", q: "Toda la estructura analítica o doctrinal en la moderna estrategia de comercialización y marketing converge imperativamente buscando un mandato y objetivo irrenunciable final que se cifra categóricamente en:", opts: ["Someter o confundir a base de tácticas inconfesables, persuasión engañosa al target para que consuma en exceso sin ninguna capacidad real de reflexión crítica logrando mermar el capital o presupuesto final del interesado inyectando productos y generando un caos irracional en su hogar y economía personal con tácticas ocultas opacas y manipulaciones encubiertas continuadas masivas en publicidad intrusiva indiscriminada engañosa o no ética.", "Identificar, anticipar e interpretar fehaciente, empática, y exitosamente los anhelos y urgencias o cubrir los carencias que el propio cliente potencial posee en todo el ciclo vital para brindarle y aportarle, mediante valor real añadido y diferencial o prestaciones sobresalientes una vía para solventarlas y satisfacer sus anhelos de forma óptima, lo que indudablemente repercute positivamente o debe lograr y retornar para el conglomerado del negocio un margen o capital en beneficios cuantiosos que sustente incesantemente su modelo de viabilidad o permanencia duradera, sólida firme y competitivamente estable a lo largo del transcurso y devenir de su historia organizativa en su ecosistema futuro general a largo alcance expansivo de forma incombustible y escalable o exponencial en la matriz corporativa global general proyectada de rentabilidad neta libre y duradera a todos sus inversores directos consolidados o plantilla interna ejecutora adscrita o la base colaborativa logística afín asociada en exclusiva del sector y entorno o área micro macro en general y local e internacional final al completo.", "Dedicar, despilfarrar de forma no estructurada o liquidar sin criterio o balance previo en los sucesivos periodos del cierre, ejercicio tras ejercicio a fondo perdido con ineficacia los ingentes sumatorios o el techo en los créditos del superávit logístico o el plan presupuestario anual proyectado obligatoriamente por normativas imperativas ineludibles por agencias sin someterse o exigir con criterio alguno auditoría interna sobre un posible y tangible ansiado, aunque ignorado, factor métrico retorno cuantificable de su enorme e ingente volumen o porcentaje inversor dinerario y de recursos aportados bajo mandatos obligatorios y coercitivos a todo el aparato publicitario departamental u orgánico burocrático y en su plantilla externa tercerizada contratada bajo convenios ineficientes generalizados.", "Realizar con enorme grado descriptivo visual estático, una captura estética del bien físico empleando o focalizando únicamente grandes o desmesurados presupuestos artísticos con grandes perfiles y modelos o en los portafolios estáticos de carácter pasivo gráfico e ilustraciones conceptuales bidimensionales exclusivas mediante sofisticados visores o catálogos y plataformas impresas sin prestar atención ineludible al encaje comercial o las especificaciones reales al por mayor al canal o la fijación estricta y distribución ni al nivel de precios finales al público de un modo absoluto carente de un hilo o rigor con los precios ofertados generalizados del sector para competir e imponer e impulsar las utilidades o atributos genuinos y verdaderos del bien principal industrial terminado en venta masiva frente a canales finales mayoristas a largo plazo para posicionar con ventas generalizadas exponenciales efectivas del departamento operativo productivo corporativo en los estamentos sociales generales de la base de una demografía de consumidores o posibles e inmediatos prospectos potenciales latentes sin conversión medible al final del canal transaccional general real en cierre facturado."], ans: 1, exp: "La gran filosofía del siglo actual, distanciándose e invalidando a los charlatanes embaucadores cortoplacistas obsoletos del pasado en épocas oscuras; la empresa y marketing del paradigma presente aboga, busca e incentiva la fidelización suprema como fin para un binomio y relación transaccional comercial pura con pacto o intercambio equilibrado justo simbiótico win win ganancia mutua: el usuario felizmente y con plena convicción solventa y satisface de raíz su problema y la organización industrial o el operador logístico corporativo afín general o el sector servicios recibe y recaba o anota un superávit de rentabilidad lícito económico con el que crece sin parar posibilitando ampliar plantilla garantizando o afianzando la supervivencia e invulnerabilidad futura al continuar aportando desarrollo a la nación estado o sociedad y al ecosistema demográfico en su conjunto general y su área limítrofe sin fisuras ni debilidades estratégicas en recesión bajo control general auditado legal ético final y permanente constante duradero y a todos sus niveles socioeconómicos y empresariales en bolsa con valor neto alto escalable e irremplazable competitivo inalcanzable para el rival directo acérrimo e inmediato imitador competidor final y competidores general." }
];
